module RefModule(
    input [7:0] A,
    input [7:0] B,
    input SEL,
    output reg [7:0] OUT
);wire [7:0] negB;
    wire __negB_tmp = (~B) + 1;
    assign negB = __negB_tmp;

    always @(*) begin
        if (SEL == 0) begin
            OUT = A + B;
        end else begin
            OUT = A + negB;
        end
    end

endmodule
